import { Hono } from 'hono'
import { getSupabaseClient, getAdminSupabaseClient } from '../../lib/supabase'

const OTP_EXPIRY_MINUTES = 5

function generateOtp(): string {
  return Math.floor(100000 + Math.random() * 900000).toString()
}

const authSendLoginOtp = new Hono()

// POST /api/auth/send-login-otp
authSendLoginOtp.post('/', async (c) => {
  const supabase = getSupabaseClient(c)
  const { data: { user }, error: authError } = await supabase.auth.getUser()
  if (authError || !user?.email) {
    return c.json({ error: 'Unauthorized' }, 401)
  }
  // NOTE: Resend API and Supabase OTP fallback are not implemented for Cloudflare Workers. Adapt this endpoint for your environment.
  return c.json({ error: 'OTP email sending not implemented in Cloudflare Workers. Use Resend API or Supabase OTP in a Node.js environment.' }, 501)
})

export default authSendLoginOtp