import { Hono } from 'hono'

const userJoinRequests = new Hono()

// GET /api/user/join-requests
userJoinRequests.get('/', async (c) => {
  // NOTE: This endpoint requires Supabase admin client.
  return c.json({ error: 'Join requests listing not implemented in Cloudflare Workers. Use Supabase admin client in a Node.js environment.' }, 501)
})

export default userJoinRequests