import { Hono } from 'hono'
import { getSupabaseClient } from '../../../../lib/supabase'

const albumsIdTeachersTeacherIdPhoto = new Hono()

// POST /api/albums/:id/teachers/:teacherId/photo
// NOTE: File upload is not implemented for Cloudflare Workers. See Hono docs for multipart support and adapt for Workers.
albumsIdTeachersTeacherIdPhoto.post('/', async (c) => {
  return c.json({ error: 'File upload not implemented in Cloudflare Workers. Use R2 or external storage and adapt this endpoint.' }, 501)
})

// DELETE /api/albums/:id/teachers/:teacherId/photo
albumsIdTeachersTeacherIdPhoto.delete('/', async (c) => {
  try {
    const supabase = getSupabaseClient(c)
    const albumId = c.req.param('id')
    const teacherId = c.req.param('teacherId')
    const { data: { user }, error: authError } = await supabase.auth.getUser()
    if (authError || !user) {
      return c.json({ error: 'Unauthorized' }, 401)
    }
    const { data: userData } = await supabase
      .from('users')
      .select('role')
      .eq('id', user.id)
      .maybeSingle()
    const isGlobalAdmin = userData?.role === 'admin'
    if (!isGlobalAdmin) {
      const { data: album, error: albumError } = await supabase
        .from('albums')
        .select('user_id')
        .eq('id', albumId)
        .maybeSingle()
      if (albumError || !album) {
        return c.json({ error: 'Album not found' }, 404)
      }
      const isOwner = album.user_id === user.id
      if (!isOwner) {
        const { data: member } = await supabase
          .from('album_members')
          .select('role')
          .eq('album_id', albumId)
          .eq('user_id', user.id)
          .maybeSingle()
        if (!member || !['admin', 'owner'].includes(member.role)) {
          return c.json({ error: 'Forbidden' }, 403)
        }
      }
    }
    const { data: teacher } = await supabase
      .from('album_teachers')
      .select('photo_url')
      .eq('id', teacherId)
      .eq('album_id', albumId)
      .maybeSingle()
    if (!teacher?.photo_url) {
      return c.json({ error: 'No photo to delete' }, 400)
    }
    try {
      const urlParts = teacher.photo_url.split('/')
      const fileName = urlParts[urlParts.length - 1]
      const bucket = 'album-photos'
      await supabase.storage
        .from(bucket)
        .remove([`teachers/${teacherId}/${fileName}`])
    } catch (error) {
      // Continue with database update even if storage deletion fails
    }
    const { error: updateError } = await supabase
      .from('album_teachers')
      .update({ photo_url: null })
      .eq('id', teacherId)
      .eq('album_id', albumId)
    if (updateError) return c.json({ error: updateError.message }, 500)
    return c.json({ success: true }, 200)
  } catch (error: any) {
    return c.json({ error: error.message || 'Internal server error' }, 500)
  }
})

export default albumsIdTeachersTeacherIdPhoto
